Here are the public test cases for feature1_ipv6_network_summary:
{
  "description": "Parse IPv6 network inputs and report the normalized network range fields, including canonical notation, range endpoints, prefix length, and address counts.",
  "cases": [
    {
      "input": {
        "address": "2001:db8::",
        "netmask": "ffff:ffff:ffff:ffff:ffff:ffff:ffff:ffff"
      },
      "expected_output": "canonical=2001:db8::/128\nnetwork=2001:db8::\nnetmask=ffff:ffff:ffff:ffff:ffff:ffff:ffff:ffff\nbroadcast=null\nfirst_usable=2001:db8::\nlast_usable=2001:db8::\ncidr=128\ntotal=1\nusable=1\n"
    },
    {
      "input": {
        "address": "2001:db8::",
        "netmask": "ffff:ffff:ffff:ffff:ffff:ffff:ffff:fffe"
      },
      "expected_output": "canonical=2001:db8::/127\nnetwork=2001:db8::\nnetmask=ffff:ffff:ffff:ffff:ffff:ffff:ffff:fffe\nbroadcast=null\nfirst_usable=2001:db8::\nlast_usable=2001:db8::1\ncidr=127\ntotal=2\nusable=2\n"
    }
  ]
}

